  molecule { v2 { disableProject(ipnftUid: $ipnftUid) { project { __typename } } } }
}

mutation ($ipnftUid: String!) {
  molecule { v2 { enableProject(ipnftUid: $ipnftUid) { project { __typename } } } }
}

mutation ($ipnftSymbol: String!, $ipnftUid: String!, $ipnftAddress: String!, $ipnftTokenId: Int!) {
  molecule {
    v2 {
      createProject(ipnftSymbol: $ipnftSymbol, ipnftUid: $ipnftUid, ipnftAddress: $ipnftAddress, ipnftTokenId: $ipnftTokenId) {
        isSuccess
        message
        __typename
        ... on CreateProjectSuccess {
          project {
            account { id accountName }
            ipnftUid
            dataRoom { id alias }
            announcements { id alias }
          }
        }
      }
    }
  }
}

mutation ($ipnftUid: String!, $path: CollectionPath!, $content: Base64Usnp!, $contentType: String!, $changeBy: String!, $accessLevel: String!, $description: String, $categories: [String!], $tags: [String!], $contentText: String, $encryptionMetadata: MoleculeEncryptionMetadataInput) {
  molecule { v2 { project(ipnftUid: $ipnftUid) { dataRoom {
    uploadFile(path: $path, content: $content, contentType: $contentType, changeBy: $changeBy, accessLevel: $accessLevel, description: $description, categories: $categories, tags: $tags, contentText: $contentText, encryptionMetadata: $encryptionMetadata) {
      isSuccess
      message
      ... on MoleculeDataRoomFinishUploadFileResultSuccess {
        entry {
          project { account { accountName } }
          path
          ref
          asVersionedFile { latest {
            version contentHash contentType changeBy accessLevel description categories tags
            encryptionMetadata { dataToEncryptHash accessControlConditions encryptedBy encryptedAt chain litSdkVersion litNetwork templateName contractVersion }
          } }
        }
      }
    }
  } } } }
}

query ($ipnftUid: String!) {
  molecule { v2 { project(ipnftUid: $ipnftUid) { dataRoom { latest { entries {
    totalCount
    nodes {
      path
      ref
      changeBy
      asVersionedFile { latest { contentType categories tags accessLevel version description } }
    }
  } } } } } }
}

